input.new_string:
home.pointerCursor = {
  gtk.enable = true;
  # x11.enable = true;
  # Hyprland 0.55 defaults to hyprcursor, but bibata-cursors ships only an
  # XCursor theme. Without a hyprcursor theme Hyprland can't resolve Bibata
  # and falls back to a generic default cursor, so have home-manager convert
  # the XCursor theme into hyprcursor format (size inherits from `size`).
  hyprcursor.enable = true;
  package = pkgs.bibata-cursors;
  name = "Bibata-Modern-Ice";
  size = 24;
};

